import 'package:dartz/dartz.dart'; import 'package:dio/dio.dart'; import 'package:myguard_frontend/core/error/exceptions.dart'; import 'package:myguard_frontend/core/error/failures.dart'; import 'package:myguard_frontend/core/network/paginated_response_model.dart'; import 'package:myguard_frontend/features/pet/data/datasources/pet_remote_datasource.dart'; import 'package:myguard_frontend/features/pet/domain/entities/pet_entity.dart'; import 'package:myguard_frontend/features/pet/domain/repositories/pet_repository.dart';

class PetRepositoryImpl implements PetRepository {
  const PetRepositoryImpl({required this.remoteDatasource}); final PetRemoteDatasource remoteDatasource;
  Failure _m(DioException e) { final er = e.error; if (er is NetworkException) return const NetworkFailure(); if (er is ServerException) return ServerFailure(er.message ?? 'Error'); return const UnknownFailure(); }
  @override Future<Either<Failure, PaginatedResponseModel<PetEntity>>> getPets({int page = 0, int size = 20, String? societyId}) async { try { return Right(await remoteDatasource.getPets(page: page, size: size, societyId: societyId)); } on DioException catch (e) { return Left(_m(e)); } catch (e) { return Left(UnknownFailure(e.toString())); } }
  @override Future<Either<Failure, PetEntity>> getPetById(String id) async { try { return Right(await remoteDatasource.getPetById(id)); } on DioException catch (e) { return Left(_m(e)); } catch (e) { return Left(UnknownFailure(e.toString())); } }
  @override Future<Either<Failure, PetEntity>> registerPet(Map<String, dynamic> data) async { try { return Right(await remoteDatasource.registerPet(data)); } on DioException catch (e) { return Left(_m(e)); } catch (e) { return Left(UnknownFailure(e.toString())); } }
  @override Future<Either<Failure, PetEntity>> updatePet(String id, Map<String, dynamic> data) async { try { return Right(await remoteDatasource.updatePet(id, data)); } on DioException catch (e) { return Left(_m(e)); } catch (e) { return Left(UnknownFailure(e.toString())); } }
  @override Future<Either<Failure, void>> deletePet(String id) async { try { await remoteDatasource.deletePet(id); return const Right(null); } on DioException catch (e) { return Left(_m(e)); } catch (e) { return Left(UnknownFailure(e.toString())); } }
  @override Future<Either<Failure, VaccinationEntity>> addVaccination(String petId, Map<String, dynamic> data) async { try { return Right(await remoteDatasource.addVaccination(petId, data)); } on DioException catch (e) { return Left(_m(e)); } catch (e) { return Left(UnknownFailure(e.toString())); } }
  @override Future<Either<Failure, List<VaccinationEntity>>> getVaccinations(String petId) async { try { return Right(await remoteDatasource.getVaccinations(petId)); } on DioException catch (e) { return Left(_m(e)); } catch (e) { return Left(UnknownFailure(e.toString())); } }
}
